mapper.select:
select notification_id, user_id, title, content, notify_type, ref_id, is_read, create_time
from biz_backpacker_notification
where user_id = #{userId}
order by create_time desc
limit #{limit}

mapper.update:
update biz_backpacker_notification
set is_read = '1'
where notification_id = #{notificationId}
  and user_id = #{userId}
